import React, { useState } from "react";
import { createVolunteer } from "../utils/api";
import { toast } from "react-toastify";

const PRESET_SKILLS = ["medical", "first-aid", "nursing", "doctor", "teaching", "education", "tutoring", "logistics", "food-distribution", "cooking", "construction", "disaster-relief", "rescue", "counseling", "training", "general-help", "driving", "communication"];

export default function AddVolunteer({ setPage }) {
  const [form, setForm] = useState({ name: "", skills: [], availability: true, address: "" });
  const [skillInput, setSkillInput] = useState("");
  const [submitting, setSubmitting] = useState(false);

  const set = (k, v) => setForm((p) => ({ ...p, [k]: v }));

  const toggleSkill = (skill) => {
    set("skills", form.skills.includes(skill) ? form.skills.filter((s) => s !== skill) : [...form.skills, skill]);
  };

  const addCustomSkill = () => {
    const s = skillInput.trim().toLowerCase().replace(/\s+/g, "-");
    if (s && !form.skills.includes(s)) {
      set("skills", [...form.skills, s]);
      setSkillInput("");
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.name || form.skills.length === 0 || !form.address) {
      toast.error("Please enter name, skills, and an address.");
      return;
    }
    try {
      setSubmitting(true);

      const geoRes = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(form.address)}`);
      const geoData = await geoRes.json();

      let lat, lng;
      if (geoData && geoData.length > 0) {
        lat = parseFloat(geoData[0].lat);
        lng = parseFloat(geoData[0].lon);
      } else {
        toast.error("Could not find that address. Please try adding city/state.");
        setSubmitting(false);
        return;
      }

      await createVolunteer({
        name: form.name,
        skills: form.skills,
        availability: form.availability,
        location: { lat, lng },
      });
      toast.success(`✓ ${form.name} registered as a volunteer!`);
      setPage("volunteers");
    } catch {
      toast.error("Failed to register volunteer. Check backend connection.");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div style={{ maxWidth: 620 }}>
      <div className="card">
        <div className="section-title">Volunteer Information</div>
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Full Name *</label>
            <input value={form.name} onChange={(e) => set("name", e.target.value)} placeholder="e.g. Ananya Singh" required />
          </div>
          <div className="form-group">
            <label>Location (Address, City, State, and Pin code) *</label>
            <input value={form.address} onChange={(e) => set("address", e.target.value)} placeholder="e.g. 123 Main St, New York, NY" required />
          </div>
          <div className="form-group">
            <label>Availability</label>
            <select value={String(form.availability)} onChange={(e) => set("availability", e.target.value === "true")}>
              <option value="true">Available</option>
              <option value="false">Unavailable</option>
            </select>
          </div>
          <div className="form-group">
            <label>Skills *</label>
            <div style={{ display: "flex", gap: 8, marginBottom: 10 }}>
              <input
                value={skillInput}
                onChange={(e) => setSkillInput(e.target.value)}
                placeholder="Type a custom skill..."
                onKeyDown={(e) => e.key === "Enter" && (e.preventDefault(), addCustomSkill())}
                style={{ flex: 1 }}
              />
              <button className="btn btn-sm" type="button" onClick={addCustomSkill}>Add</button>
            </div>
            <div style={{ display: "flex", flexWrap: "wrap", gap: 4, marginBottom: 10 }}>
              {PRESET_SKILLS.map((s) => (
                <button key={s} type="button" className={`filter-chip ${form.skills.includes(s) ? "active" : ""}`} style={{ fontSize: 11 }} onClick={() => toggleSkill(s)}>
                  {s}
                </button>
              ))}
            </div>
            {form.skills.length > 0 && (
              <div>
                <div style={{ fontSize: 11, color: "#94a3b8", marginBottom: 4 }}>Selected ({form.skills.length}):</div>
                <div style={{ display: "flex", flexWrap: "wrap", gap: 4 }}>
                  {form.skills.map((s) => (
                    <span key={s} className="skill-tag" style={{ color: "#166534", background: "#dcfce7", cursor: "pointer" }} onClick={() => toggleSkill(s)}>
                      {s} ×
                    </span>
                  ))}
                </div>
              </div>
            )}
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <button className="btn btn-primary" type="submit" disabled={submitting}>
              {submitting ? "Registering..." : "Register Volunteer"}
            </button>
            <button className="btn" type="button" onClick={() => setPage("volunteers")}>Cancel</button>
          </div>
        </form>
      </div>
    </div>
  );
}
